import java.io.*;

public class SecureDeserializationExample {

    public static void main(String[] args) {
        try {
            String userInput = "myData.ser";
            FileInputStream fileIn = new FileInputStream(userInput);
            ObjectInputStream ois = new ObjectInputStream(fileIn) {
                @Override
                protected Class<?> resolveClass(ObjectStreamClass desc) throws IOException, ClassNotFoundException {
                    String className = desc.getName();
                    if (!className.startsWith("trusted.package.")) {
                        throw new InvalidObjectException("Untrusted deserialization attempt");
                    }
                    return super.resolveClass(desc);
                }
            };

            Object obj = ois.readObject();
            System.out.println("Deserialized object: " + obj.toString());

            ois.close();
            fileIn.close();
        } catch (InvalidObjectException e) {
            System.err.println("Error during deserialization: " + e.getMessage());
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

}

### Explanation:
취약유형: Insecure Deserialization
